function sanitizeContext(context) {
  const sensitive = ['token', 'password', 'ssn', 'credit_card', 'auth'];
  // Remove sensitive fields
  return Object.keys(context).reduce((acc, key) => {
    if (!sensitive.some(s => key.toLowerCase().includes(s))) {
      acc[key] = context[key];
    }
    return acc;
  }, {});
}